// ── resolveSessionPath ──────────────────────────────────────────────
describe('resolveSessionPath', () => {
  test('returns null when project dir not found', () => {
    expect(resolveSessionPath('latest')).toBeNull();
  });

  test('resolves "latest" to most recent session', () => {
    const projDir = makeEncodedProject('/Users/test/proj');
    writeFileSync(join(projDir, 'old-session.jsonl'), '{}');
    const { utimesSync } = require('node:fs');
    utimesSync(join(projDir, 'old-session.jsonl'), new Date(2020, 0, 1), new Date(2020, 0, 1));
    writeFileSync(join(projDir, 'new-session.jsonl'), '{}');

    const result = resolveSessionPath('latest', '/Users/test/proj');
    expect(result).toBe(join(projDir, 'new-session.jsonl'));
  });

  test('resolves exact session ID', () => {
    const projDir = makeEncodedProject('/Users/test/proj');
    writeFileSync(join(projDir, 'abc-123.jsonl'), '{}');
    const result = resolveSessionPath('abc-123', '/Users/test/proj');
    expect(result).toBe(join(projDir, 'abc-123.jsonl'));
  });

  test('resolves partial session ID prefix', () => {
    const projDir = makeEncodedProject('/Users/test/proj');
    writeFileSync(join(projDir, 'abc-123-full-id.jsonl'), '{}');
    const result = resolveSessionPath('abc-123', '/Users/test/proj');
    expect(result).toBe(join(projDir, 'abc-123-full-id.jsonl'));
  });

  test('returns null for unmatched session ref', () => {
    const projDir = makeEncodedProject('/Users/test/proj');
    writeFileSync(join(projDir, 'other.jsonl'), '{}');
    expect(resolveSessionPath('no-match', '/Users/test/proj')).toBeNull();
  });

  test('returns null for "latest" when no sessions exist', () => {
    makeEncodedProject('/Users/test/proj');
    expect(resolveSessionPath('latest', '/Users/test/proj')).toBeNull();
  });
});
